### Load data


::: {.cell}

```{.r .cell-code}
library(rlang)
library(cbbplotR)

# gt save function
gt_save_crop <- function(data,
                         file = NULL,
                         bg = "white",
                         whitespace = 50,
                         zoom = 2,
                         expand = 5) {
  tmp <- tempfile(fileext = ".png")

  tryCatch({
    gtExtras::gtsave_extra(data, tmp, zoom = zoom, expand = expand)
  }, error = function(e) {
    message("gtsave_extra failed, trying gt::gtsave...")
    gt::gtsave(data, tmp, zoom = zoom, expand = expand)
  })

  magick::image_read(tmp) |> 
    magick::image_trim() |> 
    magick::image_border(bg, glue::glue('{whitespace}x{whitespace}')) |> 
    magick::image_write(file)
  unlink(tmp)
}
```
:::


### Double-digit dogs


::: {.cell}

```{.r .cell-code}
dd_dogs <- readr::read_csv("dd-dogs.csv")

dogs <- dd_dogs |>
  dplyr::arrange(Spread) |>
  dplyr::mutate(fweek = paste0("Week", " ", Week)) |>
  dplyr::select(fweek, Date, Team, Opponent, Location, Spread, fscore)


custom_header <- glue::glue(
  "<div style='display: flex; justify-content: space-between; align-items: center;'>
      <div>
       <img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-football-college.png'
       style='height: 40px; width: auto; vertical-align: middle;'>
     </div>
     <div style='flex-grow:1; margin-left: 30px; margin-right: 30px'>
       <span style='display: block; font-weight: bold; text-align: center; font-size: 24px;'>Double-digit favorites that have lost outright</span>
       <span style='font-size: 12px; font-weight: normal; display: block; text-align: center;'>2025 season through Week 8 games showing double-digit favorites that have lost outright.</span>
     </div>
     <div>
       <img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-football-college.png'
       style='height: 40px; width: auto; vertical-align: middle;'>
     </div>
   </div>
  <br>"
)



dd_tbl <- dogs |>
  cbbplotR::gt_cbb_teams(Team, Team) |>
  cbbplotR::gt_cbb_teams(Opponent, Opponent) |>
  dplyr::select(fweek, Date, Spread, Team, Opponent, Location, fscore) |>
  gt::gt() |>
  gtUtils::gt_theme_gtutils() |>
  gt::fmt_markdown(columns = c(Team, Opponent)) |>
  gtExtras::gt_merge_stack(col1 = Date, col2 = fweek) |>
  gtExtras::gt_merge_stack(col1 = fscore, col2 = Location) |>
  gt::cols_align(columns = c(Team, Opponent), align = "left") |>
  gt::cols_align(columns = c(Spread), align = "right") |>
  gtUtils::gt_column_subheaders(
    Date =  list(heading = "Date", subtitle = "Week"),
    fscore =  list(heading = "Final Score", subtitle = "Location"),
    Spread = list(heading = "Point Spread", subtitle = "Favored by?"),
    Team =  list(heading = "Favorite", subtitle = "Losing Team"),
    Location =  list(heading = "Location", subtitle = "Home/Away"),
    Opponent =  list(heading = "Underdog", subtitle = "Opponent (Winning team)"),
    heading_color = "black",
    subtitle_color = "gray"
  ) |>
  gt::tab_header(title = gt::html(custom_header)) |>
  gt::tab_source_note(
    source_note =
      gt::html(
        "<hr>Data via TeamRankings.com BetIQ | theme via {gtUtils} <br>
        Data for 2025 season through Week 8 or October 18 games.<br>
        <hr><b>Table by Chris at Bless your chart</b>"
      )
  ) |>
  gtUtils::gt_border_bars_bottom(c("#636363", "#969696", "#cccccc")) |>
  gtUtils::gt_border_grid(color = "black",
                          weight = 1,
                          include_labels = FALSE) |>
  gt::tab_style(
    locations = gt::cells_source_notes(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(10.5),
      weight = 250
    )
  ) |>
  gt::tab_style(
    style = list(gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(14)
    )),
    locations = gt::cells_body(
      rows = gt::everything(),
      columns = gt::everything()
    )
  )

gt_save_crop(dd_tbl,
             file = "dd_tbl.png",
             whitespace = 60,
             bg = "#FFFDF5")

dd_tbl
```

